Simplifica este código TypeScript que tiene sobre-ingeniería con interfaces innecesarias, abstracciones prematuras y código 'clever'. Aplica KISS, DRY, YAGNI.

```typescript
interface IProcessor<T, R> {
  process(data: T): R;
}

interface IValidator<T> {
  validate(data: T): boolean;
}

interface ILogger {
  log(message: string): void;
}

interface ICache<T> {
  get(key: string): T | undefined;
  set(key: string, value: T): void;
}

class UserData implements IValidator<UserData> {
  constructor(
    public name: string,
    public email: string,
    public age: number
  ) {}

  validate(data: UserData): boolean {
    return !!(data.name && data.email && data.age > 0);
  }
}

class UserProcessor implements IProcessor<UserData, ProcessedUser> {
  private validator: IValidator<UserData>;
  private logger: ILogger;
  private cache: ICache<ProcessedUser>;

  constructor(
    validator: IValidator<UserData>,
    logger: ILogger,
    cache: ICache<ProcessedUser>
  ) {
    this.validator = validator;
    this.logger = logger;
    this.cache = cache;
  }

  process(data: UserData): ProcessedUser {
    this.logger.log('Processing user: ' + data.name);

    const cached = this.cache.get(data.email);
    if (cached) return cached;

    if (this.validator.validate(data)) {
      const processed: ProcessedUser = {
        displayName: data.name.toUpperCase(),
        emailDomain: data.email.split('@')[1],
        isAdult: data.age >= 18,
        processedAt: new Date()
      };

      this.cache.set(data.email, processed);
      return processed;
    }

    throw new Error('Validation failed');
  }
}

interface ProcessedUser {
  displayName: string;
  emailDomain: string;
  isAdult: boolean;
  processedAt: Date;
}

// Uso
const processor = new UserProcessor(
  new UserData('', '', 0),
  console,
  new Map()
);
