package main

import "errors"

type Order struct {
    ID       string
    Customer *Customer
    Items    []Item
    Payment  *Payment
    Status   string
}

type Customer struct {
    ID       string
    IsActive bool
    Tier     string
}

type Item struct {
    ID       string
    Price    float64
    InStock  bool
}

type Payment struct {
    Method    string
    Processed bool
    Amount    float64
}

func ProcessOrder(order *Order) (*Order, error) {
    if order != nil {
        if order.Status == "pending" {
            if order.Customer != nil {
                if order.Customer.IsActive {
                    if len(order.Items) > 0 {
                        allInStock := true
                        for _, item := range order.Items {
                            if !item.InStock {
                                allInStock = false
                            }
                        }
                        if allInStock {
                            if order.Payment != nil {
                                if order.Payment.Processed {
                                    if order.Payment.Amount > 0 {
                                        // Procesar orden
                                        order.Status = "completed"
                                        return order, nil
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
    return nil, errors.New("order cannot be processed")
}
