Refactoriza este código Ruby aplicando principios de simplicidad. Tiene múltiples problemas.

```ruby
class OrderProcessor
  def initialize(config, logger, metrics, cache, validator, notifier)
    @config = config
    @logger = logger
    @metrics = metrics
    @cache = cache
    @validator = validator
    @notifier = notifier
  end

  def process(order, user, payment, shipping, discount_code, referral_code, metadata)
    @logger.info("Processing order for user: #{user.id}")

    if @validator.valid?(order)
      if user.active?
        if payment.sufficient_funds?(order.total)
          if shipping.valid_address?
            discount = calculate_discount(order, discount_code, referral_code, user.tier)

            total = order.total - discount

            transaction = process_payment(payment, total)

            if transaction.success?
              shipment = create_shipment(order, shipping)

              if shipment.created?
                @metrics.record('order.success')
                @notifier.send(:email, user, :order_confirmed)
                @notifier.send(:sms, user, :order_confirmed) if user.sms_enabled?
                @notifier.send(:push, user, :order_confirmed) if user.push_enabled?

                return {
                  success: true,
                  order_id: order.id,
                  transaction_id: transaction.id,
                  shipment_id: shipment.id,
                  total: total,
                  discount: discount,
                  metadata: metadata
                }
              end
            end
          end
        end
      end
    end

    @metrics.record('order.failure')
    { success: false }
  end

  private

  def calculate_discount(order, code, referral, tier)
    discount = 0
    discount += 10 if code == 'SAVE10'
    discount += 5 if referral
    discount += tier == 'gold' ? 20 : tier == 'silver' ? 10 : 0
    [discount, order.total * 0.5].min
  end

  def process_payment(payment, amount)
    payment.charge(amount)
  end

  def create_shipment(order, shipping)
    shipping.create(order)
  end
end
